Review the following Express.js API endpoint for security vulnerabilities, performance issues, and code quality:

```javascript
const express = require('express');
const app = express();
const db = require('./db');

app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;
  const user = await db.query(`SELECT * FROM users WHERE username = '${username}' AND password = '${password}'`);
  if (user.rows.length > 0) {
    const token = username + Date.now();
    res.json({ token, user: user.rows[0] });
  } else {
    res.json({ error: 'Invalid credentials' });
  }
});

app.get('/api/users/:id', async (req, res) => {
  const user = await db.query(`SELECT * FROM users WHERE id = ${req.params.id}`);
  res.json(user.rows[0]);
});

app.get('/api/users', async (req, res) => {
  const users = await db.query('SELECT * FROM users');
  const result = [];
  for (const user of users.rows) {
    const orders = await db.query(`SELECT * FROM orders WHERE user_id = ${user.id}`);
    result.push({ ...user, orders: orders.rows });
  }
  res.json(result);
});

app.listen(3000);
```

